from flask import Flask, request, session, redirect, url_for, jsonify
from functools import wraps
import secrets
import time

app = Flask(__name__)
app.secret_key = "replace-with-a-secure-random-secret"

USERS = {
    "alice": {
        "password": "password123",
        "mfa_secret": "123456"
    },
    "bob": {
        "password": "securepass",
        "mfa_secret": "654321"
    }
}

MFA_CHALLENGES = {}
MFA_TIMEOUT_SECONDS = 300

def create_mfa_challenge(username):
    challenge_id = secrets.token_urlsafe(16)
    MFA_CHALLENGES[challenge_id] = {
        "username": username,
        "created_at": time.time(),
        "verified": False
    }
    return challenge_id

def get_challenge(challenge_id):
    challenge = MFA_CHALLENGES.get(challenge_id)
    if not challenge:
        return None
    if time.time() - challenge["created_at"] > MFA_TIMEOUT_SECONDS:
        MFA_CHALLENGES.pop(challenge_id, None)
        return None
    return challenge

def login_required(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        if not session.get("authenticated"):
            return jsonify({"error": "Authentication required"}), 401
        return f(*args, **kwargs)
    return wrapper

def mfa_required(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        if not session.get("authenticated"):
            return jsonify({"error": "Authentication required"}), 401
        if not session.get("mfa_verified"):
            return jsonify({"error": "MFA required"}), 403
        return f(*args, **kwargs)
    return wrapper

@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or request.form
    username = data.get("username")
    password = data.get("password")

    user = USERS.get(username)
    if not user or user["password"] != password:
        return jsonify({"error": "Invalid username or password"}), 401

    challenge_id = create_mfa_challenge(username)

    session.clear()
    session["authenticated"] = True
    session["username"] = username
    session["mfa_verified"] = False
    session["mfa_challenge_id"] = challenge_id
    session["password_verified_at"] = int(time.time())

    return redirect(url_for("verify_mfa"))

@app.route("/verify-mfa", methods=["GET", "POST"])
@login_required
def verify_mfa():
    challenge_id = session.get("mfa_challenge_id")
    challenge = get_challenge(challenge_id)

    if not challenge or challenge["username"] != session.get("username"):
        session.clear()
        return jsonify({"error": "MFA challenge expired or invalid"}), 401

    if request.method == "GET":
        return jsonify({
            "message": "Submit MFA code to complete verification",
            "mfa_verified": session.get("mfa_verified", False)
        })

    data = request.get_json(silent=True) or request.form
    code = data.get("code")
    username = session.get("username")
    user = USERS.get(username)

    if not user or code != user["mfa_secret"]:
        return jsonify({"error": "Invalid MFA code"}), 401

    challenge["verified"] = True
    session["mfa_verified"] = True

    return jsonify({
        "message": "MFA verification successful",
        "username": username
    })

